package com.example.fingerprintauth;

import android.content.Intent;
import android.os.Bundle;
import android.content.SharedPreferences;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ImageButton;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;

import java.util.concurrent.Executor;

public class MainActivity extends AppCompatActivity {

    private EditText usernameEditText, passwordEditText;
    private Button loginButton;
    private ImageButton biometricLoginButton;
    private TextView settingsLink;

    private SharedPreferences sharedPreferences;
    private BiometricPrompt biometricPrompt;
    private BiometricPrompt.PromptInfo promptInfo;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        usernameEditText = findViewById(R.id.username_edit_text);
        passwordEditText = findViewById(R.id.password_edit_text);
        loginButton = findViewById(R.id.login_button);
        biometricLoginButton = findViewById(R.id.biometric_login_button);
        settingsLink = findViewById(R.id.settings_link);

        sharedPreferences = AppConstants.getSharedPreferences(this);

        // Initialize BiometricPrompt
        Executor executor = ContextCompat.getMainExecutor(this);
        biometricPrompt = new BiometricPrompt(MainActivity.this,
                executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                super.onAuthenticationError(errorCode, errString);
                Toast.makeText(getApplicationContext(), "Authentication error: " + errString, Toast.LENGTH_SHORT).show();
                // Optionally, show password login fields if not already visible
            }

            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                Toast.makeText(getApplicationContext(), "Biometric authentication succeeded!", Toast.LENGTH_SHORT).show();
                navigateToHome();
            }

            @Override
            public void onAuthenticationFailed() {
                super.onAuthenticationFailed();
                Toast.makeText(getApplicationContext(), "Authentication failed.", Toast.LENGTH_SHORT).show();
            }
        });

        // Prompt info for login
        promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("App Login")
                .setSubtitle("Log in using your biometric credential")
                .setNegativeButtonText("Use password") // Provides a fallback to password if biometric is cancelled
                .build();

        loginButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                // Dummy password login for demonstration
                if (usernameEditText.getText().toString().equals("user") &&
                    passwordEditText.getText().toString().equals("pass")) {
                    Toast.makeText(MainActivity.this, "Password login successful!", Toast.LENGTH_SHORT).show();
                    navigateToHome();
                } else {
                    Toast.makeText(MainActivity.this, "Invalid credentials.", Toast.LENGTH_SHORT).show();
                }
            }
        });

        biometricLoginButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                attemptBiometricLogin();
            }
        });

        settingsLink.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                Intent intent = new Intent(MainActivity.this, SettingsActivity.class);
                startActivity(intent);
            }
        });
    }

    @Override
    protected void onResume() {
        super.onResume();
        // Update biometric button visibility when activity resumes (e.g., after changing settings)
        updateBiometricButtonVisibility();
    }

    private void updateBiometricButtonVisibility() {
        boolean isBiometricEnabled = sharedPreferences.getBoolean(AppConstants.KEY_BIOMETRIC_ENABLED, false);
        BiometricManager biometricManager = BiometricManager.from(this);
        int canAuthenticate = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG | BiometricManager.Authenticators.BIOMETRIC_WEAK);

        if (isBiometricEnabled && canAuthenticate == BiometricManager.BIOMETRIC_SUCCESS) {
            biometricLoginButton.setVisibility(View.VISIBLE);
        } else {
            biometricLoginButton.setVisibility(View.GONE);
            // If biometric was enabled but now no biometrics are enrolled, notify user
            if (isBiometricEnabled && canAuthenticate == BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED) {
                Toast.makeText(this, "Biometric login was enabled but no biometrics are enrolled. Please check device settings.", Toast.LENGTH_LONG).show();
            }
        }
    }

    private void attemptBiometricLogin() {
        BiometricManager biometricManager = BiometricManager.from(this);
        int canAuthenticate = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG | BiometricManager.Authenticators.BIOMETRIC_WEAK);

        if (canAuthenticate == BiometricManager.BIOMETRIC_SUCCESS) {
            biometricPrompt.authenticate(promptInfo);
        } else {
            String errorMessage = "Biometric authentication not available or configured.";
            switch (canAuthenticate) {
                case BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE:
                    errorMessage = "No biometric hardware detected on this device.";
                    break;
                case BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE:
                    errorMessage = "Biometric hardware is currently unavailable.";
                    break;
                case BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED:
                    errorMessage = "No biometrics enrolled. Please enroll a fingerprint or face in device settings.";
                    break;
                case BiometricManager.BIOMETRIC_ERROR_SECURITY_UPDATE_REQUIRED:
                    errorMessage = "A security update is required to use biometrics.";
                    break;
                case BiometricManager.BIOMETRIC_ERROR_UNSUPPORTED:
                    errorMessage = "Biometric authentication is not supported on this device.";
                    break;
                case BiometricManager.BIOMETRIC_STATUS_UNKNOWN:
                    errorMessage = "Unknown biometric status.";
                    break;
            }
            Toast.makeText(this, errorMessage, Toast.LENGTH_LONG).show();
            // Ensure the button is hidden if biometric is not genuinely available
            biometricLoginButton.setVisibility(View.GONE);
            // Also update the shared preference if it was enabled but now impossible
            if (sharedPreferences.getBoolean(AppConstants.KEY_BIOMETRIC_ENABLED, false)) {
                 sharedPreferences.edit().putBoolean(AppConstants.KEY_BIOMETRIC_ENABLED, false).apply();
            }
        }
    }

    private void navigateToHome() {
        Intent intent = new Intent(MainActivity.this, HomeActivity.class);
        // Clear back stack so user can't go back to login screen with back button
        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }
}
package com.example.fingerprintauth;

import android.os.Bundle;
import android.content.SharedPreferences;
import android.widget.CompoundButton;
import android.widget.Switch;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;

import java.util.concurrent.Executor;

public class SettingsActivity extends AppCompatActivity {

    private Switch biometricSwitch;
    private SharedPreferences sharedPreferences;
    private BiometricPrompt biometricPrompt;
    private BiometricPrompt.PromptInfo promptInfo;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_settings);

        biometricSwitch = findViewById(R.id.biometric_switch);
        sharedPreferences = AppConstants.getSharedPreferences(this);

        // Initialize BiometricPrompt for enabling/disabling in settings
        Executor executor = ContextCompat.getMainExecutor(this);
        biometricPrompt = new BiometricPrompt(SettingsActivity.this,
                executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                super.onAuthenticationError(errorCode, errString);
                Toast.makeText(getApplicationContext(), "Authentication error: " + errString, Toast.LENGTH_SHORT).show();
                // Revert switch state if authentication failed or cancelled during enabling
                if (biometricSwitch.isChecked()) {
                    biometricSwitch.setChecked(false);
                }
            }

            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                // Authentication succeeded, save state to SharedPreferences
                sharedPreferences.edit().putBoolean(AppConstants.KEY_BIOMETRIC_ENABLED, true).apply();
                Toast.makeText(getApplicationContext(), "Biometric login enabled!", Toast.LENGTH_SHORT).show();
            }

            @Override
            public void onAuthenticationFailed() {
                super.onAuthenticationFailed();
                Toast.makeText(getApplicationContext(), "Authentication failed.", Toast.LENGTH_SHORT).show();
                // Revert switch state if authentication failed during enabling
                if (biometricSwitch.isChecked()) {
                    biometricSwitch.setChecked(false);
                }
            }
        });

        // Prompt info for enabling biometric (initial confirmation)
        promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("Enable Biometric Login")
                .setSubtitle("Confirm your identity to enable biometric login")
                .setNegativeButtonText("Cancel")
                .build();

        // Set initial state of the switch based on SharedPreferences
        boolean isBiometricEnabled = sharedPreferences.getBoolean(AppConstants.KEY_BIOMETRIC_ENABLED, false);
        biometricSwitch.setChecked(isBiometricEnabled);

        biometricSwitch.setOnCheckedChangeListener(new CompoundButton.OnCheckedChangeListener() {
            @Override
            public void onCheckedChanged(CompoundButton buttonView, boolean isChecked) {
                if (isChecked) {
                    // User wants to enable biometric login
                    checkBiometricCompatibilityAndPrompt();
                } else {
                    // User wants to disable biometric login
                    sharedPreferences.edit().putBoolean(AppConstants.KEY_BIOMETRIC_ENABLED, false).apply();
                    Toast.makeText(SettingsActivity.this, "Biometric login disabled.", Toast.LENGTH_SHORT).show();
                }
            }
        });
    }

    private void checkBiometricCompatibilityAndPrompt() {
        BiometricManager biometricManager = BiometricManager.from(this);
        switch (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG | BiometricManager.Authenticators.BIOMETRIC_WEAK)) {
            case BiometricManager.BIOMETRIC_SUCCESS:
                // Biometric authentication is available and configured, proceed with prompt
                biometricPrompt.authenticate(promptInfo);
                break;
            case BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE:
                Toast.makeText(this, "No biometric hardware detected on this device.", Toast.LENGTH_LONG).show();
                biometricSwitch.setChecked(false); // Revert switch
                break;
            case BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE:
                Toast.makeText(this, "Biometric hardware is currently unavailable.", Toast.LENGTH_LONG).show();
                biometricSwitch.setChecked(false); // Revert switch
                break;
            case BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED:
                Toast.makeText(this, "No biometrics enrolled. Please enroll a fingerprint or face in device settings.", Toast.LENGTH_LONG).show();
                biometricSwitch.setChecked(false); // Revert switch
                // Option to guide user to settings:
                // final Intent enrollIntent = new Intent(Settings.ACTION_BIOMETRIC_ENROLL);
                // enrollIntent.putExtra(Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED, BiometricManager.Authenticators.BIOMETRIC_STRONG | BiometricManager.Authenticators.BIOMETRIC_WEAK);
                // startActivity(enrollIntent);
                break;
            case BiometricManager.BIOMETRIC_ERROR_SECURITY_UPDATE_REQUIRED:
                Toast.makeText(this, "A security update is required to use biometrics.", Toast.LENGTH_LONG).show();
                biometricSwitch.setChecked(false); // Revert switch
                break;
            case BiometricManager.BIOMETRIC_ERROR_UNSUPPORTED:
                Toast.makeText(this, "Biometric authentication is not supported on this device.", Toast.LENGTH_LONG).show();
                biometricSwitch.setChecked(false); // Revert switch
                break;
            case BiometricManager.BIOMETRIC_STATUS_UNKNOWN:
                Toast.makeText(this, "Unknown biometric status.", Toast.LENGTH_LONG).show();
                biometricSwitch.setChecked(false); // Revert switch
                break;
        }
    }
}
